<template>
    <div>
    <q-img
    v-if="(props.src!=='')&&(props.src!==null)&&(props.src!==undefined)&&props.src"
        :src="props.src"
        :ratio="1"
        height="80px"
        width="80px"
    >
    <q-badge @click="deleteImg" color="red" transparent rounded><q-icon name='close'></q-icon></q-badge>

    </q-img>
    <p v-else>
       <!-- <Uploader :index="props.index" :col="props.col" :hide-upload-btn="false" @upload-success="handleUploadSuccess" @upload-error="handleUploadError" @upload=""/>-->
        <Uploader
        :index="props.index"
        :col="props.col"
        :hide-upload-btn="false"
        
        @upload-success="handleUploadSuccess"
        @upload-error="handleUploadError"
        >
        <template #uploading="{ isUploading }">
            <div v-if="isUploading">
            Uploading: {{ uploadProgress }}%
            </div>
        </template>
        </Uploader>
    </p>
    </div>  
</template>
<script>
import Uploader from '../Uploader.vue'
export default {
    name:"AdminImage",
    components: {
        Uploader
    },
    props:{
        props: {
            type: Object,
            required: true
        },
    },
    methods:{
        handleUploadError(err){
        console.log(err)
        },
        handleUploadSuccess(index,url) {
        console.log('handleUploadSuccess')
        var payload = {
            index: index,
            value: url,
            col: this.props.col
        }
        this.$emit('update', payload)
    },
    deleteImg(){
        console.log("called")
        var payload = {
            index: this.props.index,
            value: null,
            col: this.props.col
        }
        this.$emit('update', payload)

    }
    }
}
</script>